const raw = $input.first().json;
const rows = Array.isArray(raw) ? raw : [];
if (rows.length === 0) return [{ json: { _empty: true } }];
const now = Date.now();
const out = [];
for (const r of rows) {
  if (!r.expires_date) continue;
  const days = Math.floor((new Date(r.expires_date).getTime() - now) / 86400000);
  let next = 'current';
  let notify = false;
  if (days < 0) { next = 'expired'; notify = true; }
  else if (days <= 1) { next = 'expiring_7d'; notify = (r.renewal_status !== 'expiring_7d' || days === 1); }
  else if (days <= 7) { next = 'expiring_7d'; notify = (r.renewal_status !== 'expiring_7d'); }
  else if (days <= 14) { next = 'expiring_14d'; notify = (r.renewal_status !== 'expiring_14d'); }
  else if (days <= 30) { next = 'expiring_30d'; notify = (r.renewal_status !== 'expiring_30d'); }
  else if (days <= 60) { next = 'expiring_60d'; notify = (r.renewal_status !== 'expiring_60d'); }
  if (next !== r.renewal_status) {
    out.push({ json: { license_id: r.id, advisor_id: r.advisor_id, license_type: r.license_type, jurisdiction: r.jurisdiction, expires_date: r.expires_date, days_to_expiry: days, new_status: next, notify: notify } });
  }
}
if (out.length === 0) return [{ json: { _empty: true, reason: 'no transitions' } }];
return out;
